import {
  createContext,
  useContext,
  useRef,
  type PropsWithChildren,
} from 'react';

import { buildOverlay } from '../overlay.js';
import type { Overlay } from '../types.js';

export const OverlayContext = createContext<Overlay>({} as Overlay);

/**  @internal  */
export const useOverlay = () => {
  const overlayState = useContext(OverlayContext);

  if (!overlayState) {
    throw new Error('useOverlay not used within OverlayContext provider.');
  }

  return overlayState;
};

/**  @internal  */
export const OverlayProvider = (props: PropsWithChildren) => {
  const overlayRef = useRef<HTMLDivElement>();
  const overlay = useRef<Overlay>();
  overlay.current ||= buildOverlay(overlayRef);

  return (
    <OverlayContext.Provider value={overlay.current}>
      {props.children}
    </OverlayContext.Provider>
  );
};
